// Validate required fields and normalize schema
const body = $json.body || $json;

// Support both old schema (order_items) and Order Received schema (cart_items)
const orderItems = body.order_items || body.cart_items || [];
const hasOrderItems = Array.isArray(orderItems) && orderItems.length > 0;

const required = ['customer_name','email','phone'];
const missing = required.filter(k => !body[k] || (Array.isArray(body[k]) && body[k].length === 0));
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

if (!hasOrderItems) {
  throw new Error('order_items or cart_items must be a non-empty array');
}

// Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  throw new Error('Invalid email format');
}

// Validate phone format (basic US format)
const phoneDigits = String(body.phone).replace(/\D/g, '');
if (phoneDigits.length < 10 || phoneDigits.length > 11) {
  throw new Error('Invalid phone number');
}

// Normalize items to internal format
const normalizedItems = orderItems.map(item => {
  // Support both schemas:
  // Old: { item_id, name, qty, price (dollars) }
  // Order Received: { id, display_name, quantity, base_price_cents, modifiers }
  const itemId = item.item_id || item.id || 'unknown';
  const name = item.name || item.display_name || 'Unknown Item';
  const qty = item.qty || item.quantity || 1;

  // Price: prefer cents, fall back to dollars
  let priceCents;
  if (item.base_price_cents !== undefined) {
    priceCents = item.base_price_cents;
  } else if (item.unit_price_cents !== undefined) {
    priceCents = item.unit_price_cents;
  } else if (item.price !== undefined) {
    priceCents = Math.round(item.price * 100);
  } else {
    priceCents = 0;
  }

  return {
    item_id: itemId,
    name: name,
    qty: Number(qty),
    price_cents: priceCents,
    price_dollars: priceCents / 100,
    modifiers: item.modifiers || []
  };
});

// Normalize totals
let subtotalCents, taxCents, totalCents;

if (body.subtotal_cents !== undefined) {
  // Order Received schema (cents)
  subtotalCents = body.subtotal_cents;
  taxCents = body.tax_cents || Math.round(subtotalCents * 0.0952);
  totalCents = body.total_cents || (subtotalCents + taxCents);
} else {
  // Old schema (dollars)
  const subtotal = body.subtotal || normalizedItems.reduce((s, i) => s + (i.price_dollars * i.qty), 0);
  const tax = body.tax || Math.round(subtotal * 0.0952 * 100) / 100;
  const total = body.total || (subtotal + tax);
  subtotalCents = Math.round(subtotal * 100);
  taxCents = Math.round(tax * 100);
  totalCents = Math.round(total * 100);
}

// Validate totals
if (subtotalCents < 0 || taxCents < 0 || totalCents < 0) {
  throw new Error('Totals cannot be negative');
}

const calcTotal = subtotalCents + taxCents;
if (Math.abs(calcTotal - totalCents) > 2) {
  throw new Error(`Total mismatch: ${subtotalCents} + ${taxCents} != ${totalCents}`);
}

// Build normalized payload
const normalized = {
  customer_name: body.customer_name,
  email: body.email,
  phone: body.phone,
  pickup_time: body.pickup_time || body.pickup_time_actual || 'ASAP',
  special_instructions: body.special_instructions || body.notes || '',
  source: body.source || 'web',
  timestamp: body.timestamp || new Date().toISOString(),
  order_items: normalizedItems,
  subtotal_cents: subtotalCents,
  tax_cents: taxCents,
  total_cents: totalCents,
  subtotal: subtotalCents / 100,
  tax: taxCents / 100,
  total: totalCents / 100
};

return [{ json: normalized }];

// Hours gate: check pickup_time against business hours
const TIMEZONE = 'America/Chicago';
const HOURS = {
  mon: { open: '12:30', close: '19:30' },
  tue: { open: '12:30', close: '19:30' },
  wed: { open: '12:30', close: '19:30' },
  thu: { open: '12:30', close: '19:30' },
  fri: { open: '12:30', close: '19:30' },
  sat: { open: '12:30', close: '19:30' },
  sun: null // Closed Sunday
};

const body = $json;
const pickupTime = body.pickup_time || 'ASAP';

// If ASAP, use current time + 30 min lead time
let checkTime = pickupTime;
let isAsap = false;
if (checkTime === 'ASAP' || !checkTime) {
  isAsap = true;
  const now = new Date();
  const cst = new Date(now.toLocaleString('en-US', { timeZone: TIMEZONE }));
  // Add 30 minutes kitchen lead time
  cst.setMinutes(cst.getMinutes() + 30);
  const h = String(cst.getHours()).padStart(2, '0');
  const m = String(cst.getMinutes()).padStart(2, '0');
  checkTime = h + ':' + m;
}

// Parse pickup time
const [pickupHour, pickupMin] = checkTime.split(':').map(Number);
const pickupMinutes = pickupHour * 60 + pickupMin;

// Get current day in CST
const now = new Date();
const cst = new Date(now.toLocaleString('en-US', { timeZone: TIMEZONE }));
const dayNames = ['sun','mon','tue','wed','thu','fri','sat'];
const today = dayNames[cst.getDay()];
const hours = HOURS[today];

if (!hours) {
  throw new Error('Deli is closed today');
}

const [openHour, openMin] = hours.open.split(':').map(Number);
const [closeHour, closeMin] = hours.close.split(':').map(Number);
const openMinutes = openHour * 60 + openMin;
const closeMinutes = closeHour * 60 + closeMin;

const isOpen = pickupMinutes >= openMinutes && pickupMinutes <= closeMinutes;

if (!isOpen) {
  throw new Error('Pickup time ' + checkTime + ' is outside business hours (' + hours.open + ' - ' + hours.close + ' CT)');
}

return [{ json: Object.assign({}, body, { in_hours: true, pickup_time_actual: checkTime, is_asap: isAsap }) }];

// Generate order_id: UDO-YYYYMMDD-###
const body = $json;
const now = new Date();
const cst = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
const ymd = cst.toISOString().slice(0,10).replace(/-/g, '');

// Use counter or random 3-digit number
const seq = String(Math.floor(Math.random() * 900) + 100).padStart(3, '0');
const order_id = `UDO-${ymd}-${seq}`;

return [{ json: { ...body, order_id, idempotency_key: order_id } }];

// Build Square line items from normalized order_items
const body = $json;

const square_line_items = body.order_items.map(item => {
  const lineItem = {
    name: item.name,
    quantity: String(item.qty),
    base_price_money: {
      amount: item.price_cents,
      currency: 'USD'
    },
    modifiers: []
  };

  // Add modifiers if present
  if (Array.isArray(item.modifiers)) {
    item.modifiers.forEach(mod => {
      const deltaCents = Math.round(Number(mod.price_delta || 0) * 100);
      lineItem.modifiers.push({
        name: mod.mod_name || mod.name || 'Modifier',
        base_price_money: {
          amount: deltaCents,
          currency: 'USD'
        }
      });
    });
  }

  return lineItem;
});

// Add tax as line item (like Order Received does)
const square_line_items_with_tax = [
  ...square_line_items,
  {
    name: 'Tax',
    quantity: '1',
    base_price_money: {
      amount: body.tax_cents,
      currency: 'USD'
    }
  }
];

return [{ json: { ...body, square_line_items, square_line_items_with_tax } }];

